#import <Foundation/Foundation.h>
#include "BleDataMarcos.h"

@interface XPBLEData : NSObject

@property (nonatomic, strong) NSArray<NSData *> *data;
@property (nonatomic, strong) NSArray<NSData *> *tboxData;

@end

@interface XPBLEDataProcessor : NSObject

/// 蓝牙包解析
/// - Parameters:
///   - vehicleCode: 车型编码Code
///   - bleData: 蓝牙包
///   return: json字符串
+ (NSString *)parseMessageWithVehicleCode:(NSString *)vehicleCode 
                                  bleData:(NSData *)bleData;


/// 生成蓝牙 发送数据
/// - Parameters:
///   - payload: 待发数据
///   - controlId: 车控指令 Id 号
///   - vehicleTypeCode: 车型码
///   - msgType: BLE 消息类型（含车控消息和和其他类型消息）
///   - controlType: BLE 车控消息类型
+ (XPBLEData *)generateBleData:(NSData *)payload
                     controlId:(uint8_t)controlId
               vehicleTypeCode:(NSString *)vehicleTypeCode
                       msgType:(BLEKeyMessageType)msgType
                   controlType:(BLEKeyMsgControlHeaderMessageType)controlType;

/// 生成鉴权数据包，不包含 frame header
/// - Parameters:
///   - random1: 随机数1
///   - random2: 随机数2
///   - macAddress: mac 地址
+ (NSData *)generateAuthData:(uint32_t)random1 
                     random2:(uint32_t)random2
                  macAddress:(NSString *)macAddress;

/// 为鉴权数据添加 header
/// - Parameters:
///   - data: 数据包
///   - isDoublesided:是否双向认证
+ (XPBLEData *)addAuthFrameHeader:(NSData *)data 
                 isDoublesided:(BOOL)isDoublesided;

/// 生成tbox token
/// - Parameters:
///   - code: code
///   - controlId: controlId
///   - packageSize: packageSize
+ (NSArray<NSData *> *)createTboxMessageWith:(BLEBoxCommand )cmd
                                   keyString:(NSString *)keyString
                                    controlId:(uint8_t)controlId
                                    packageSize:(int8_t)packageSize;


/// 生成 parking心跳消息
/// - Parameters:
///   - cmd: 心跳指令
///   - count: count
+ (NSData *)createParkingHeartbeatMessageWith:(BLEParkingCommand)cmd
                                        count:(uint8_t)count;
@end

