import Foundation
import CocoaMQTT

@objc(XPMQTTHandlerDelegate)
public protocol MQTTHandlerDelegate: NSObjectProtocol {
    /// 连接状态变更 Available / disconnected / connecting
    @objc optional func didChangeState(state: MQTTConnectionState)
    /// 收到订阅 topic 消息
    @objc optional func didReceiveSubscribTopicMessage(topic: String, msg: [String : Any])
    /// 收到订阅 topic 消息
    @objc optional func didReceiveSubscribTopicMessage(topic: String, msgString: String?)
    /// 收到mqtt消息
    @objc optional func didReceiveMessage(topic: String, msg: [String : Any])
    /// 收到mqtt  消息
    @objc optional func didReceiveMessage(topic: String, msgString: String?)
    /// 订阅 成功 失败 回调
    @objc optional func didSubscribeTopics(success: [String], failed: [String])
}

@objc(XPMQTTHandler)
open class MQTTHandler : NSObject {

    private let mqttPublisher: MQTTPublisher = MQTTPublisher.sharedInstance
    @objc public var publishTopic: String? = ""
    @objc public var subscribTopics: Set<String> = []
    private let delegateQueue: DispatchQueue
    private var callbackManager: MQTTHandlerCallbackInfoManager = MQTTHandlerCallbackInfoManager()
    private var resendManager: MQTTHandlerCallbackInfoManager = MQTTHandlerCallbackInfoManager()

    @objc public weak var delegate: MQTTHandlerDelegate?
    private var _publishTopic: String {
        if let publishTopic {
            return publishTopic
        } else {
            return ""
        }
    }

    private var defaultMessageId: UInt16 = 100

    @objc public var state: MQTTConnectionState {
        get {
            return state(with: mqttPublisher.state)
        }
    }
    @objc public var isConnected: Bool { return state == .Available }

    @objc public init( publishTopic: String?, subscribTopics: [String]? = nil, delegateQueue: DispatchQueue? = DispatchQueue.main) {
        if let subscribTopics {
            self.subscribTopics.formUnion(subscribTopics)
        }
        self.delegateQueue = delegateQueue ?? DispatchQueue.main
        self.publishTopic = publishTopic ?? ""
        super.init()
        setupMqtt()
        resendManager.errorType = .disconnected
    }

    deinit {
        callbackManager.getCallbacks().forEach { info in
            info.callback(nil, MQTTHandlerError.error(with: .deinitError))
        }

        mqttPublisher.removeDelegate(delegate: self)
    }

    /// 发布消息
    /// - Parameters:
    ///   - message: 参数
    ///   - messageId: 消息id
    ///   - timeOutTime: 超时时间 默认15s， 当开启重连时，最大超时默认30s
    ///   - needReconnect: 是否需要在连接断开时重连, 默认 true 需要重连
    ///   - callback: callback
    @discardableResult
    @objc public func publish(message: String,
                        messageId: String? = nil,
                        timeOutTime: TimeInterval = 15,
                        needReconnect: Bool = true,
                        callback: MQTTHandlerCallback? = nil) -> Bool {
        guard isConnected else {
            if needReconnect {
                // 重连，连上继续发送
                connectAndResend(message: message, messageId: messageId, timeOutTime: timeOutTime, callback: callback)
                return true
            }
            callback?(nil, MQTTHandlerError.error(with: .disconnected))
            return false
        }
        return _publish(message: message,
                        messageId: messageId,
                        timeOutTime: timeOutTime,
                        callback: callback)
    }

    /// 发布消息
    /// - Parameters:
    ///   - mqttParams: 参数
    ///   - needReconnect: 是否需要在连接断开时重连, 默认 true 需要重连
    ///   - callback: callback
    @objc public func publish(mqttParams: MQTTParams,
                 needReconnect: Bool = true,
                 callback: MQTTHandlerCallback? = nil) {
        publish(message: mqttParams.messagBody,
                messageId: mqttParams.messageId,
                timeOutTime: mqttParams.timeOutTime,
                needReconnect: needReconnect,
                callback: callback)
    }

    @objc public func connect(timeout: TimeInterval = 5) {
        guard self.state == .NotConnected else { return }
        DispatchQueue.main.async {
            self.mqttPublisher.connect(timeout: timeout)
        }
    }

    @objc public func disconnect() {
        mqttPublisher.disconnect()
    }
}


// MARK: - private
extension MQTTHandler {

    private func _publish(message: String,
                        messageId: String? = nil,
                        timeOutTime: TimeInterval = 5,
                        callback: MQTTHandlerCallback? = nil) -> Bool {
        var cManager = callbackManager

        if let callback {
            guard let messageId else {
                callback(nil, MQTTHandlerError.error(with: .parameterError))
                return false
            }
            cManager.addCallbackInfo(messageId,
                                            message: message,
                                            timeoutTime: timeOutTime,
                                            callback: callback)
        }
        mqttPublisher.publish(message: message, topic: self._publishTopic)
        return true
    }

    private func connectAndResend(message: String,
                          messageId: String? = nil,
                                  timeOutTime: TimeInterval = 5.0,
                          callback: MQTTHandlerCallback? = nil) {
        var _callback: MQTTHandlerCallback = { _,_ in }
        resendManager.addCallbackInfo(messageId ?? String(defaultMessageId),
                                      message: message,
                                      timeoutTime: timeOutTime,
                                      callback: callback ?? _callback)
        defaultMessageId += 1
        _ = connect()
    }

    private func resendIfNeed() {
        resendManager.getCallbacks().forEach { callbackInfo in
            publish(message: callbackInfo.message,
                    messageId: callbackInfo.messageId,
                    timeOutTime: callbackInfo.timeoutTime,
                    callback: callbackInfo.callback)
        }
    }

    private func setupMqtt() {
        mqttPublisher.addDelegate(delegate: self)
    }

    private func handleRecieveMsg(string: String?) -> [String:Any] {
        guard let string else {  return [:]  }
        guard let data = string.data(using: .utf8) else { return [:]  }
        do {
            let json = try JSONSerialization.jsonObject(with: data, options: .allowFragments)
            if let json = json as? [String:Any] {
                return json
            } else {
                return [:]
            }
        } catch {
            return [:]
        }
    }

    func state(with cocoaState: MQTTPublisherConnectionState) -> MQTTConnectionState {
        switch cocoaState {
        case .connected:
            return .Available
        case .connecting:
            return .Connecting
        case .disconnected:
            return .NotConnected
        }
    }
}


extension MQTTHandler: MQTTPublisherDelegate {
    public func didConnectAck(ack: MQTTConnAck) {

    }

    public func didPublishMessage(topic: String, string: String?) {

    }

    public func didReceiveMessage(topic: String, string: String?) {

        // 检查callback
        let json = handleRecieveMsg(string: string)

        delegateQueue.async { [weak self] in
            guard let self else { return }

            if self.subscribTopics.contains(topic) {
                self.delegate?.didReceiveSubscribTopicMessage?(topic: topic, msg: json)
                self.delegate?.didReceiveSubscribTopicMessage?(topic: topic, msgString: string)
            }
            self.delegate?.didReceiveMessage?(topic: topic, msg: json)
            self.delegate?.didReceiveMessage?(topic: topic, msgString: string)

            var messageId = json["msg_ref"] as? String

            var service_type = json["service_type"] as? Int
            var msg_content = json["msg_content"] as? [String: Any]
            var digital_vehicle = msg_content?["digital_vehicle"] as? [String: Any]
            var instant = msg_content?["instant"] as? [String: Any]
            var interval = msg_content?["interval"] as? [String: Any]

            // 兼容MobileXp topic数据结构
            if topic.hasPrefix(MQTTIronRecieveMessagePoint) {
                messageId = json["msgRef"] as? String
            } else if topic.hasPrefix(MonaMQTTRecievePoint) {
                // 兼容mona mqtt消息数据结构
                messageId = json["msgId"] as? String
            }

            guard let messageId = messageId, !messageId.isEmpty else { return }

            if (service_type == 19 && digital_vehicle != nil && instant == nil && interval == nil) {
                return
            }

            if let callback = callbackManager.getCallback(messageId) {
                callbackManager.removeCallbackInfo(messageId)
                callback(json, nil)
            }
        }
    }

    public func didChangeState(state: MQTTPublisherConnectionState) {
        if state == .connected {
            resendIfNeed()
        }
        delegateQueue.async {
            self.delegate?.didChangeState?(state: self.state(with: state))
        }
    }

    public func didSubscribeTopics(success: NSDictionary, failed: [String]) {
        if let topics = success.allKeys as? [String] {
            delegateQueue.async {
                self.delegate?.didSubscribeTopics?(success: topics, failed: failed)
            }
        }
    }

    public func didUnsubscribeTopics(topics: [String]) {
    }

    public func didDisconnect(error: Error?) {
    }
}

