import Foundation
import CocoaMQTT
import Network

@objc(XPMQTTPublisherConnectionState)
public enum MQTTPublisherConnectionState: Int {

    case disconnected = 0

    case connecting

    case connected
}

@objc(XPMQTTConnAck)
public enum MQTTConnAck: Int {

    case accept = 0

    case unacceptableProtocolVersion

    case identifierRejected

    case serverUnavailable

    case badUsernameOrPassword

    case notAuthorized

    case reserved
}

@objc(XPMQTTPublisherDelegate)
public protocol MQTTPublisherDelegate: NSObjectProtocol {
    @objc optional func didConnectAck(ack: MQTTConnAck)
    @objc optional func didPublishMessage(topic: String, string: String?)
    @objc optional func didReceiveMessage(topic: String, string: String?)
    @objc optional func didChangeState(state: MQTTPublisherConnectionState)
    @objc optional func didSubscribeTopics(success: NSDictionary, failed: [String])
    @objc optional func didUnsubscribeTopics(topics: [String])
    @objc optional func didDisconnect(error: Error?)
}

public protocol MQTTPublisherInfoProtocol: NSObjectProtocol {
    var clientID: String? { get }
    var serverUrl: NSURL? { get }
    var clientCertPath: String? { get }
    var serverCertPath: String? { get }
    var username: String? { get }
    var password: String? { get }
    var subscribeTopics: [String]? { get }
    var clientCertKey: String? { get }
    func refreshInfo()
    var connectIfNeed: Bool { get }
}

@objc(XPMQTTPublisher)
open class MQTTPublisher : NSObject {
    var statisticsModel = StatisticsMqttModel()

    @objc public static let sharedInstance = MQTTPublisher()

    @objc public dynamic var state: MQTTPublisherConnectionState = .disconnected
    @objc public var isConnected: Bool { return state == .connected }
    weak public var mqttInfo: MQTTPublisherInfoProtocol?

    public var delegateQueue: DispatchQueue = DispatchQueue.main
    public var subscriptions: [String: CocoaMQTTQoS] {
        mqttClient?.subscriptions ?? [:]
    }
    private var isSubscribing = false
    private var isSubscribed = false
    let semaphore = DispatchSemaphore(value: 1)

    private override init() {
        super.init()
    }

    private var mqttClient: CocoaMQTT? {
        didSet {
            state = MQTTPublisherConnectionState.fromCocoaMQTTConnState(mqttClient?.connState ?? .disconnected, isSubscribed: false)
        }
    }

    private var delegate: MulticastDelegate = MulticastDelegate<MQTTPublisherDelegate>()
    private let libDelegateQueue = DispatchQueue(label: "MQTTDelegateQueue")

    private func initMqttIfneed(clientID: String,
                                host: String,
                                port: UInt16,
                                username: String,
                                password: String) {
        mqttClient?.disconnect()
        state = .disconnected
        mqttClient = CocoaMQTT(clientID: clientID, host: host, port: port)
        mqttClient?.password = password
        mqttClient?.username = username
    }

    @objc public func setupMqtt() -> Bool {
        semaphore.wait()
        guard let clientID = mqttInfo?.clientID, let serverUrl = mqttInfo?.serverUrl, let username = mqttInfo?.username, let password = mqttInfo?.password else {
            Log.i("MQTTPublisher setupMqtt url error")
            semaphore.signal()
            return false
        }
        guard let host = serverUrl.host, let port = serverUrl.port else {
            Log.i("MQTTPublisher setupMqtt url error")
            semaphore.signal()
            return false
        }

        Log.i("setupMqtt clientID: \(clientID) host: \(host) port: \(port) username: \(username) password: \(password)")
        initMqttIfneed(clientID: clientID, host: host, port: port.uint16Value, username: username, password: password)

        mqttClient?.delegateQueue = libDelegateQueue
        mqttClient?.enableSSL = true
        mqttClient?.allowUntrustCACertificate = true
        mqttClient?.delegate = self

        if let clientCertArray = getClientCertFromP12File() {
            var sslSettings: [String: NSObject] = [:]
            sslSettings[kCFStreamSSLCertificates as String] = clientCertArray
            mqttClient?.sslSettings = sslSettings
        }

        #if DEBUG
        mqttClient?.logLevel = .debug
        #endif

        isSubscribing = false
        isSubscribed = false
        semaphore.signal()

        return true
    }
    @discardableResult
    @objc public func connect() -> Bool {
        connect(timeout: -1)
    }

    @discardableResult
    @objc public func connect(timeout: TimeInterval) -> Bool {
        if !(mqttInfo?.connectIfNeed ?? false) {
            Log.w("连接过程 监测到 connectIfNeed 为 false,  拒绝连接")
            return false
        }
        if mqttInfo?.username == nil || mqttInfo?.password == nil {
            Log.e("连接过程 username 或 password 为空, 不登录")

            semaphore.wait()
            isSubscribing = false
            isSubscribed = false
            semaphore.signal()
            return false
        }

        // 重设账号信息
        if state == .disconnected {
            setupMqtt()
        }

        Log.i("发起连接")
        if mqttClient?.connState == .disconnected {
            trackingConnectStart()
        }
        return mqttClient?.connect(timeout: timeout) ?? false
    }

    /// 断开连接
    /// - Parameter cleanInfo: 是否清空登录信息 ， 默认 true， 清空后将无法直接connect ，需重新执行 setupMqtt 重新设置数据
    @objc public func disconnect() {
        Log.i("mqtt 主动 disconnec")

        semaphore.wait()
        isSubscribing = false
        isSubscribed = false
        semaphore.signal()
        trackingDisconnect()
        mqttClient?.disconnect()
    }

    @objc public func addDelegate(delegate: MQTTPublisherDelegate) {
        self.delegate += delegate
    }

    @objc public func removeDelegate(delegate: MQTTPublisherDelegate) {
        self.delegate -= delegate
    }

    @objc public func publish(message: String, topic: String) {
        Log.i("======= mqtt 发送消息 =======\n", "Topic: \(topic)\n", "消息内容:\n", (message.jsonFormatPrint() ?? ""))
        mqttClient?.publish(topic, withString: message, qos: .qos2, retained: false)
    }

    func subscribe(topics: [String]) {
        semaphore.wait()
        if isSubscribing || isSubscribed {
            semaphore.signal()
            return
        }
        isSubscribing = true
        semaphore.signal()

        Log.i("subscribe \(topics)")
        let topArr = topics.map { topic in
            (topic, CocoaMQTTQoS.qos2)
        }
        statisticsModel.subscribStartTime = Date().timeIntervalSince1970
        mqttClient?.subscribe(topArr)
    }

    private func subscribeIfneed() {
        guard  let subscribTopics = mqttInfo?.subscribeTopics,
               subscribTopics.count > 0 else { return  }
        subscribe(topics: Array(subscribTopics))
    }

    private func connectAck(with ack: CocoaMQTTConnAck) -> MQTTConnAck {
        switch ack {
        case .accept:
            return .accept
        case .badUsernameOrPassword:
            return .badUsernameOrPassword
        case .identifierRejected:
            return .identifierRejected
        case .notAuthorized:
            return .notAuthorized
        case .reserved:
            return .reserved
        case .serverUnavailable:
            return .serverUnavailable
        case .unacceptableProtocolVersion:
            return .unacceptableProtocolVersion
        @unknown default:
            return .reserved
        }
    }

}

extension MQTTPublisherConnectionState {
    static func fromCocoaMQTTConnState(_ state: CocoaMQTTConnState, isSubscribed: Bool) -> MQTTPublisherConnectionState {
        switch state {
        case .connected:
            return isSubscribed ? .connected : connecting
        case .connecting:
            return .connecting
        case .disconnected:
            return .disconnected
        @unknown default:
            return .disconnected
        }
    }
}

extension MQTTPublisher: CocoaMQTTDelegate {
    public func mqtt(_ mqtt: CocoaMQTT, didStateChangeTo state: CocoaMQTTConnState) {
        Log.i("MQTTState didStateChangeTo \(state) ")

        semaphore.wait()
        let publisherState = MQTTPublisherConnectionState.fromCocoaMQTTConnState(state, isSubscribed: isSubscribed)
        self.state = publisherState
        semaphore.signal()

        delegateQueue.async {
            self.delegate.invoke { $0.didChangeState?(state: publisherState) }
        }

        if state == .connected {
            subscribeIfneed()
            trackingConnectSuccess()
        }

        if state == .disconnected {
            semaphore.wait()
            isSubscribing = false
            isSubscribed = false
            semaphore.signal()
        }
    }

    public func mqtt(_ mqtt: CocoaMQTT, didSubscribeTopics success: NSDictionary, failed: [String]) {
        Log.i("MQTTSubscribe didSubscribeTopics  success:  \(success) failed: \(failed)")

        delegateQueue.async {
            self.delegate.invoke { $0.didSubscribeTopics?(success: success, failed: failed) }
        }
        semaphore.wait()
        isSubscribing = false
        semaphore.signal()
        statisticsModel.subscribEndTime = Date().timeIntervalSince1970
        if success.count > 0 {
            semaphore.wait()
            isSubscribed = true
            let publisherState = MQTTPublisherConnectionState.fromCocoaMQTTConnState(.connected, isSubscribed: isSubscribed)
            self.state = publisherState
            semaphore.signal()

            delegateQueue.async {
                self.delegate.invoke { $0.didChangeState?(state: publisherState) }
            }
            trackingSubscribeSuccess()
        } else {
            trackingSubscribeError()
            // 隔一秒重试
            DispatchQueue.main.asyncAfter(deadline: .now() + 1) { [weak self] in
                self?.subscribeIfneed()
            }
        }
    }

    public func mqtt(_ mqtt: CocoaMQTT, didUnsubscribeTopics topics: [String]) {
        Log.i("MQTTSubscribe didUnsubscribeTopics \(topics)")

        delegateQueue.async {
            self.delegate.invoke { $0.didUnsubscribeTopics?(topics: topics)}
        }
    }

    public func mqtt(_ mqtt: CocoaMQTT, didConnectAck ack: CocoaMQTTConnAck) {
        Log.i("MQTTState didConnectAck \(ack)")

        delegateQueue.async {
            self.delegate.invoke { $0.didConnectAck?(ack: self.connectAck(with: ack)) }
        }

        // 服务端拒绝连接（一般是账号密码问题），清理登录信息重连
        if ack == .badUsernameOrPassword || ack == .notAuthorized {
            self.mqttInfo?.refreshInfo()
        }
    }

    public func mqtt(_ mqtt: CocoaMQTT, didPublishMessage message: CocoaMQTTMessage, id: UInt16) {
        Log.i("didPublishMessage", message.string ?? "")

        delegateQueue.async {
            self.delegate.invoke { $0.didPublishMessage?(topic: message.topic, string: message.string) }
        }
    }

    public func mqttDidDisconnect(_ mqtt: CocoaMQTT, withError err: Error?) {
        Log.i("mqttDidDisconnect", err?.localizedDescription ?? "")

        delegateQueue.async {
            self.delegate.invoke { $0.didDisconnect?(error: err) }
        }

        let error = err as NSError?
        trackingConnectLost(code: error?.code ?? 1, message: error?.localizedDescription)
    }

    public func mqtt(_ mqtt: CocoaMQTT, didPublishAck id: UInt16) {
        Log.i("didPublishAck: \(id)")
    }

    public func mqtt(_ mqtt: CocoaMQTT, didPublishComplete id: UInt16) {
        Log.i("didPublishComplete: \(id)")
    }

    public func mqtt(_ mqtt: CocoaMQTT, didReceiveMessage message: CocoaMQTTMessage, id: UInt16) {
        Log.i("======= mqtt 收到消息 =======\n", "Topic: \(message.topic)\n", "消息内容:\n", (message.string?.jsonFormatPrint() ?? ""))

        delegateQueue.async {
            self.delegate.invoke { $0.didReceiveMessage?(topic: message.topic, string: message.string) }
        }
    }

    public func mqttDidPing(_ mqtt: CocoaMQTT) {
        Log.i("mqttDidPing ")
    }

    public func mqttDidReceivePong(_ mqtt: CocoaMQTT) {
        Log.i("mqttDidReceivePong ")
    }

    public func mqtt(_ mqtt: CocoaMQTT, didReceive trust: SecTrust, completionHandler: @escaping (Bool) -> Void) {
        Log.i("trust start")
        guard let certPath = mqttInfo?.serverCertPath else {
            Log.e("trust error: certPath = nil")
            completionHandler(false)
            return
        }
        if let certData = NSData(contentsOfFile: certPath) {
            if let cert = SecCertificateCreateWithData(nil, certData) {
                SecTrustSetAnchorCertificates(trust, [cert] as CFArray)

                var result = false
                var error: CFError?
                result = SecTrustEvaluateWithError(trust, &error)

                completionHandler(result)
            } else {
                Log.e("trust error")
                completionHandler(false)
            }
        } else {
            Log.e("trust error")
            completionHandler(false)
        }
    }
}

extension MQTTPublisher {
    func getClientCertFromP12File() -> CFArray? {
            // get p12 file path
        let resourcePath = mqttInfo?.clientCertPath

        guard let certPassword = mqttInfo?.clientCertKey,
              let filePath = resourcePath,
              let p12Data = NSData(contentsOfFile: filePath) else {
            Log.e("Failed to open the certificate file: resourcePath")
            return nil
        }

        // create key dictionary for reading p12 file
        let key = kSecImportExportPassphrase as String
        let options : NSDictionary = [key: certPassword]

        var items : CFArray?
        let securityError = SecPKCS12Import(p12Data, options, &items)

        guard securityError == errSecSuccess else {
            if securityError == errSecAuthFailed {
                Log.e("ERROR: SecPKCS12Import returned errSecAuthFailed. Incorrect password?")
            } else {
                Log.e("Failed to open the certificate file: \(resourcePath).p12")
            }
            return nil
        }

        guard let theArray = items, CFArrayGetCount(theArray) > 0 else {
            return nil
        }

        let dictionary = (theArray as NSArray).object(at: 0)
        guard let identity = (dictionary as AnyObject).value(forKey: kSecImportItemIdentity as String) else {
            return nil
        }
        let certArray = [identity] as CFArray

        return certArray
    }
}

