import Foundation

extension MQTTPublisher {
    func trackingSubscribeSuccess() {

        statisticsModel.duration = Int64((statisticsModel.connectEndTime - statisticsModel.connectStartTime) * 1000)         
        statisticsModel.car_type = XPVehicleSDK.currentVehicle()?.vehiclePreference.vehicleTypeCode
        Statistics.trackingMqttSubscrioe(model: statisticsModel)
    }

    func trackingSubscribeError() {

        statisticsModel.duration = Int64((statisticsModel.connectEndTime - statisticsModel.connectStartTime) * 1000)
        statisticsModel.car_type = XPVehicleSDK.currentVehicle()?.vehiclePreference.vehicleTypeCode
        statisticsModel.result = 0
        Statistics.trackingMqttSubscrioe(model: statisticsModel)
    }

    func trackingConnectStart() {
        statisticsModel.connectStartTime = Date().timeIntervalSince1970
        statisticsModel.action = "start"
        statisticsModel.car_type = XPVehicleSDK.currentVehicle()?.vehiclePreference.vehicleTypeCode
        statisticsModel.error_code = 0
        statisticsModel.duration = 0

        statisticsModel.error_message = ""
        statisticsModel.transaction_id = UUID().uuidString+Date().description
        Statistics.trackingMqttConnect(model: statisticsModel)
    }

    func trackingConnectFail(code: Int, message: String?) {
        statisticsModel.connectEndTime = Date().timeIntervalSince1970
        statisticsModel.action = "fail"
        statisticsModel.car_type = XPVehicleSDK.currentVehicle()?.vehiclePreference.vehicleTypeCode

        statisticsModel.duration = Int64((statisticsModel.connectEndTime - statisticsModel.connectStartTime) * 1000) 
        statisticsModel.error_code = code
        statisticsModel.error_message = message ?? ""
        Statistics.trackingMqttConnect(model: statisticsModel)
        statisticsModel.is_first_time  = 0
    }

    func trackingConnectSuccess() {
        statisticsModel.connectEndTime = Date().timeIntervalSince1970
        statisticsModel.action = "succeed"
        statisticsModel.car_type = XPVehicleSDK.currentVehicle()?.vehiclePreference.vehicleTypeCode
        statisticsModel.duration = Int64((statisticsModel.connectEndTime - statisticsModel.connectStartTime) * 1000)
        statisticsModel.error_code = 0
        statisticsModel.error_message = ""
        Statistics.trackingMqttConnect(model: statisticsModel)
        statisticsModel.is_first_time  = 0
    }

    func trackingDisconnect() {
        statisticsModel.connectEndTime = Date().timeIntervalSince1970
        statisticsModel.action = "disconnect"
        statisticsModel.car_type = XPVehicleSDK.currentVehicle()?.vehiclePreference.vehicleTypeCode
        statisticsModel.duration = Int64((statisticsModel.connectEndTime - statisticsModel.connectStartTime) * 1000)        
        statisticsModel.error_code = 0
        statisticsModel.error_message = ""
        Statistics.trackingMqttConnect(model: statisticsModel)
        statisticsModel.is_first_time  = 0
    }

    func trackingConnectLost(code: Int, message: String?) {
        if statisticsModel.action == "disconnect" {
           return
        }

        statisticsModel.connectEndTime = Date().timeIntervalSince1970
        statisticsModel.action = "lost"
        statisticsModel.car_type = XPVehicleSDK.currentVehicle()?.vehiclePreference.vehicleTypeCode

        statisticsModel.duration = Int64((statisticsModel.connectEndTime - statisticsModel.connectStartTime) * 1000)  
        statisticsModel.error_code = code

        statisticsModel.code = 1
        if !NetworkMonitor.shared.isNetworkReachable() {
            statisticsModel.code = 2
        }

        statisticsModel.error_message = message ?? ""
        Statistics.trackingMqttConnect(model: statisticsModel)
        statisticsModel.is_first_time  = 0
    }
}

