import Foundation
import MMKV
import Combine

@objc(XPMQTTLoginInfo)
public class MQTTLoginInfo: NSObject {
    public var clientID: String
    public var serverSsl: String
    public var certPath: String
    public var username: String
    public var password: String
    @objc public init(clientID: String, serverSsl: String, certPath: String, username: String, password: String) {
        self.clientID = clientID
        self.serverSsl = serverSsl
        self.certPath = certPath
        self.username = username
        self.password = password
    }
}

@objc(XPMqttServiceManager)
public class MqttServiceManager: NSObject {
    @objc public static let shared = MqttServiceManager()
    var uid: UInt64?
    // 锁
    let semaphore = DispatchSemaphore(value: 1)
    var isRequesting = false

    var disconnectMQTTTimer: Timer?
    var cancellables = Set<AnyCancellable>()
    var mqttAccountModel: MqttAccountModel?

    var requestTime: TimeInterval?

    public override init() {
        super.init()

        // 断开/重连业务逻辑
        if (self.responds(to: Selector(("addMQTTDisReconnMonitor")))) {
            self.perform(Selector(("addMQTTDisReconnMonitor")))
        }
        MQTTPublisher.sharedInstance.mqttInfo = self
    }

    func deinited() {
        self.disconnectMQTTTimer?.invalidate()
        self.disconnectMQTTTimer = nil
        NotificationCenter.default.removeObserver(self)
    }


    @objc public func startService(uid: UInt64) {
        // 0为 当前非登录 断开服务
        if uid == 0 {
            stopService()
            return
        }
        semaphore.wait()

        // 已连接返回
        if uid == self.uid && MQTTPublisher.sharedInstance.state == .connected {
            semaphore.signal()
            return
        }
        if let old = self.uid, old != 0, uid != 0 {
            if MQTTPublisher.sharedInstance.state == .connected {
                MQTTPublisher.sharedInstance.disconnect()
            }
            isRequesting = false
        }

        self.uid = uid
        mqttAccountModel = MqttAccountModel.load(uid: uid)

