@objc(XPVehicleSwitchedObject)
public class VehicleSwitchedObject : NSObject {
    @objc public let vin: String
    @objc public let presenter: VehiclePresenter? // 可能为空

    init(_ vin: String, _ presenter: VehiclePresenter?) {
        self.vin = vin
        self.presenter = presenter
    }

    public override var description: String {
        return "VehicleSwitchedObject<vin:\(self.vin) presenter:\(self.presenter)>"
    }
}


@objc(XPVehicleManager)
open class VehicleManager : NSObject {

    // 车辆列表变化，当需要监听从有车到无车事件时，可监听该事件
    @objc public let vehicleListChangedEvent: VehicleEvent = VehicleEvent(valueType: [VehicleData].self)

    // 将要切车，参数为 vin
    @objc public let vehicleWillSwitchEvent: VehicleEvent = VehicleEvent(valueType: String.self)

    // 切车事件，参数中的 VehiclePresenter, 可能为 nil，vin 不会为空
    @objc public let vehicleSwitchedEvent: VehicleCurrentEvent = VehicleCurrentEvent(valueType: VehicleSwitchedObject.self)
    // 如果某业务直接监听 vehicleSwitchedEvent，可能导致比主模块先收到该事件，
    // 为了让业务层可以有一个优先收到切车事件的模块，SDK 发出 vehicleSwitchedEvent
    // 通知后，紧接着就会发送 vehicleInfoUpdatedEvent 通知，因此大多数业务只需要
    // 监听 vehicleInfoUpdatedEvent，处理 UI 刷新即可。

    // 当前车辆车辆信息发生了变更，例如车图、软件能力等信息变更，会再次发出 vehicleInfoUpdatedEvent
    //  value: true - 表示真实发生了信息变更
    //         false - 表示跟随 vehicleSwitchedEvent 一起发出的通知
    @objc public let vehicleInfoUpdatedEvent: VehicleEvent = VehicleEvent(valueType: Bool.self)

    @objc public let extInfoChangedEvent: VehicleEvent = VehicleEvent(valueType: VehicleExtInfo.self)

    // 以下事件均为当前车相应状态变化才会发出通知
    // 切车时，也会发送车态变化事件(含离线切车，以及App离线启动)，此时 diff 车态里的字段全部为 nil
    @objc public let vehicleStateChangedEvent: VehicleCurrentEvent = VehicleCurrentEvent(valueType: VehicleStateNotiObject.self)
    @objc public let digitVehicleStateChangedEvent: VehicleCurrentEvent = VehicleCurrentEvent(valueType: DigitVehicleStateNotiObject.self)

    @objc public let onlineStateChangedEvent: VehicleEvent = VehicleEvent(valueType: Bool.self)
    @objc public let digitalKeyChangedEvent: VehicleEvent = VehicleEvent(valueType: DigitalKeyChangeType.self)

    @objc public let bleConnectStateChangedEvent: VehicleEvent = VehicleEvent(valueType: BLEConnectionState.self)
    @objc public let mqttConnectStateChangedEvent: VehicleEvent = VehicleEvent(valueType: MQTTConnectionState.self)

    @objc public let otaStateChangedEvent: VehicleEvent = VehicleEvent(valueType: OTAStateModel.self)

    @objc public let bleSysStateChangedEvent: VehicleEvent = VehicleEvent(valueType: BLESysState.self)

    @objc public let carkeyEntryStateChangedEvent: VehicleCurrentEvent = VehicleCurrentEvent(valueType: CarKeyPollingSwitchState.self)

    @objc public let pollingFuncEventChangedEvent: VehicleCurrentEvent = VehicleCurrentEvent(valueType: PollingFunctionEventModel.self)

    /// 车型配置化发生了变化（OCM平台上车型配置化能力发生了变化）
    @objc public let vehicleAbilityConfigChangedEvent: VehicleCurrentEvent = VehicleCurrentEvent(valueType: Bool.self)

    // 是否 SDK 2.0开放车型
    @objc open func isOpenedVehicleTypeCode(_ code: String) -> Bool {
        // SDK 2.0 开放的车型列表
#if !APP_ENV_INTL
    #if !DEBUG
        let openedCodeList = ["DM", "EE", "FF", "FE", "FC", "EH", "HE", "HR", "FH", "FK", "FJ", "EF", "FA", "EA", "DP", "HA", "DF", "GA", "DG", "GB"];

    #else
        let openedCodeList = ["DM", "EE", "FF", "FE", "FC", "EH", "HE", "HR", "FH", "FK", "FJ", "EF", "FA", "EA", "DP", "HA", "DF", "GA", "DG", "GB"];
    #endif

        return openedCodeList.contains(code);
#else
        return true; // 海外版开放所有车型
#endif
    }

    // 当前车是否在开放列表中
    func isCurrentVehicleOpened() -> Bool {
        return isOpenedVehicleTypeCode(self.currentInfoVehicle?.vehicleTypeCode ?? "");
    }

    @objc open var vehicleDataList: [VehicleData] {
        return _vehicleDataList.snapshot
    }

    private var _vehicleDataList: ThreadSafeList<VehicleData> = ThreadSafeList<VehicleData>() // 对外车辆列表接口
    @objc open var currentVehicleData: VehicleData? {
        return vehicleDataForVin(self.currentInfoVehicle?.vin ?? "")
    }

    var currentInfoVehicle: VehicleInfo.Vehicle?;
    var vehicleInfo: VehicleInfo? // 内部车辆信息
    public var uid: UInt64 = 0 // 用户账号

    var vehicleInstance: BaseVehicle? // 当前车控实例

    var isSwitching: Bool = false // 是否正在切车

    @objc dynamic open var bleSysState: BLESysState = .Unknown

    var cancellables = Set<AnyCancellable>()
    let eventCancellableSet = EventCancellableSet()

    var currentVehicleVinKey: String = "currentVehicleVin"

    let switchVehicleQueue = DispatchQueue(label: "VehicleManager.switchVehicle", qos: .userInitiated)

    public override init() {
        super.init()
        print("VehicleManager init")
    }

import Foundation


public protocol BaseVehicle: VehiclePresenter, VehiclePresenterExt, VehicleCommunication {

    func startService()
    func stopService()

    // 切到其他车，stopService然后注销iBeacon，但不会删除钥匙
    func leaveVehicle()


    func updateVehicleInfo(vehicle: VehicleInfo.Vehicle, vehiclePreference: VehiclePreference)

    // 请求哨兵视频列表
    func requestSentinelVideoList(_ success: VehicleSuccessResponseCallback?, failed: VehicleFailedCallback<VehicleError>?);

    // 请求车端OTA升级状态（仅针对不支持数字车态的车型，目前只有mona车在用）
    func requestOTAState(_ success: VehicleSuccessResponseCallback?, failed: VehicleFailedCallback<VehicleError>?);

}

