func deinited() {
    print("VehicleManager deinited")
    self.close()
    NotificationCenter.default.removeObserver(self)
}

func setup() {
    Log.i("VehicleManager setup")
    self.bleSysState = BLESysState(rawValue: BleCentral.shared.bleState.rawValue) ?? .Unknown

    BleCentral.shared.$bleState.dropFirst().sink {[weak self] state in
        let sysState = BLESysState(rawValue: state.rawValue) ?? .Unknown
        Log.i("系统蓝牙状态变化：", sysState)
        self?.bleSysState = sysState
        self?.bleSysStateChangedEvent.send(sysState)
        NotificationCenter.default.post(name: VehicleNotification.BLESysStateChanged, object:nil, userInfo: ["state": BLESysStateNotiObject(bleSysState: sysState)])
    }
    .store(in: &cancellables)

    NotificationCenter.default.addObserver(self, selector: #selector(carkeyPollingSwitchChanged), name: VehicleNotification.kGetCarKeyPassiveEntrySwitchResult, object: nil)
}

@objc func carkeyPollingSwitchChanged(noti: Notification) {
    Log.i("carkeySession", "polling switch changed")
    let state = noti.userInfo?["pollingState"] ?? CarKeyPollingSwitchState.Unknown
    self.carkeyEntryStateChangedEvent.send(state)
}

func closeCurrentVehicle() {
    self.cancelCurrentVehicleEventObserver();
    vehicleInstance?.leaveVehicle()
    self.vehicleInstance?.stopService()
    self.vehicleInstance = nil

}

func clearVehicles() {
    Log.i("VehicleManager clearVehicles")

    let vehicleList = self._vehicleDataList.snapshot
    if (vehicleList.count > 0) {
        vehicleList.forEach { vehicleData in
            vehicleData.invalid = true;
        }
        self._vehicleDataList.clear()
        self.vehicleListChangedEvent.send(self.vehicleDataList);
    }

    self.vehicleInfo = nil

    self.currentInfoVehicle = nil;
}

func close() {
    Log.i("VehicleManager close")

    closeCurrentVehicle();
    clearVehicles()

    self.uid = 0
}

// 创建一个不受 VehicleManager 管控的车控实例，可以在不切车进行多车车控
// 创建实例后，需要业务方调用 startService() 才会连接车辆
// 使用完毕后需要调用 stopService()
@objc public func createVehicle(vin: String) -> VehiclePresenter? {

    guard let vehicle = findVehicle(vin) else {
        Log.w("VehicleManager createVehicle 失败，车辆列表中未找到vin:", vin)
        return nil;
    }

    if (!isOpenedVehicleTypeCode(vehicle.vehicleTypeCode ?? "")) {
        Log.w("VehicleManager createVehicle 非2.0开放车型不支持创建车控实例 vin:", vin, "TypeCode:", vehicle.vehicleTypeCode)
        return nil;
    }

    if (vehicle.vehicleTypeCode == "DM") {
        Log.w("VehicleManager createVehicle Mona车型不支持创建车控实例 vin:", vin, "TypeCode:", vehicle.vehicleTypeCode)
        return nil;
    }

    var vehicleInst: BaseVehicle? = nil;
    let vehicleData = self.vehicleDataForVin(vehicle.vin ?? "") as? VehiclePreference
    if (vehicleData != nil) {
        if (vehicle.isMona()) {
            vehicleInst = MonaVehicle(uid: self.uid, vehicle: vehicle, vehiclePreference: vehicleData!)
        } else {
            vehicleInst = XiaopengVehicle(uid: self.uid, vehicle: vehicle, vehiclePreference: vehicleData!)
        }
    }

    return vehicleInst;
}


// 将模型转换为字典
func encodeToDictionary(model: Codable) -> [String: Any]? {
    let jsonData = try? JSONEncoder().encode(model)
